module priority_encoder_3bit (D, Y, invalid);
input [2:0] D;
output reg [1:0] Y;
output reg invalid;

always @(*) begin
    if (D[2]) begin
        Y = 2'b10;
        invalid = 1'b1;
    end
    else if (D[1]) begin
        Y = 2'b01;
        invalid = 1'b1;
    end
    else if (D[0]) begin
        Y = 2'b00;
        invalid = 1'b1;
    end
    else begin
        Y = 2'b00;
        invalid = 1'b0;
    end
end

endmodule
